// ============================================================
// Phase 1.1 – Ingress & Deterministic Intent Detection
// Place this code in an n8n Code Node directly after a Webhook.
// It normalises the incoming payload and classifies the intent
// using strict keyword/regex matching (no LLMs).
// ============================================================

// 1. Safely extract the body from the first incoming item
const body = $input.first()?.json?.body || {};

// 2. Normalise fields – always provide safe defaults
const user   = body.user_id || body.user || 'unknown';
const amount = parseFloat(body.amount) || 0;
const message = body.message || '';

// ============================================================
// INTENT DETECTION MATRIX (deterministic, case‑insensitive)
// ============================================================
// Each regex uses word boundaries (\b) to avoid false partial matches.
// 
// *** HOW TO ADD RUSSIAN / UZBEK KEYWORDS LATER ***
// Simply insert the required Cyrillic/Latin alternatives inside the
// parentheses of the relevant regex, separated by a pipe (|).
//
//   Example (Russian transfer keywords):
//   /\b(transfer|send|pay|p2p|перевод|отправить|платить)\b/i
//
//   Example (Uzbek transfer keywords):
//   /\b(transfer|send|pay|p2p|o'tkazish|jo'natish|to'lash)\b/i
//
//   Feel free to mix all languages in the same pattern.
// ============================================================

const TRANSFER_REGEX      = /\b(transfer|send|pay|p2p)\b/i;
const ACCESS_REGEX        = /\b(login|password|block|freeze|access)\b/i;
const PAYMENT_ISSUE_REGEX = /\b(failed|error|refund|missing)\b/i;

let intent = 'general_inquiry';

// Evaluate in strict order – first match wins
if (TRANSFER_REGEX.test(message)) {
  intent = 'transfer_request';
} else if (ACCESS_REGEX.test(message)) {
  intent = 'access_issue';
} else if (PAYMENT_ISSUE_REGEX.test(message)) {
  intent = 'payment_issue';
}

// ============================================================
// 3. Output the canonical JSON for downstream nodes
// ============================================================
return {
  json: {
    user,
    amount,
    intent,
    risk_level: "PENDING",   // will be enriched by the next node
    status: "PENDING"        // will be updated later in the workflow
  }
};

// ============================================================
// Phase 1.2 – Risk Standardization & Triage Gate
// Place after the intent detection node.  Expects canonical
// payload: { user, amount, intent, risk_level, status }
// ============================================================

// 1. Retrieve the incoming item
const ticket = $input.first().json;

// 2. Safely coerce amount to a number (0 if missing/unparseable)
let amount = parseFloat(ticket.amount);
if (isNaN(amount)) amount = 0;

// 3. Preserve intent and user (already normalised)
const intent = ticket.intent || 'general_inquiry';
const user   = ticket.user   || 'unknown';

// 4. Apply Sovereign Limits in strict order – first match prevails
let risk_level = '';
let status     = '';

// --- Rule 1: The Block (above 50M UZS) ---
if (amount > 50000000) {
  risk_level = 'BLOCKED';
  status     = 'REJECTED_HARD_LIMIT';
}
// --- Rule 2: The Challenge (≥ 10M UZS) ---
else if (amount >= 10000000) {
  risk_level = 'HIGH';
  status     = 'PENDING_BIOMETRIC';
}
// --- Rule 3: Security Intent (access_issue) ---
else if (intent === 'access_issue') {
  risk_level = 'HIGH';
  status     = 'PENDING_HUMAN_REVIEW';
}
// --- Rule 4: Failed Payment Issue ---
else if (intent === 'payment_issue') {
  risk_level = 'MED';
  status     = 'PENDING_AUTO_RESOLUTION';
}
// --- Default: Low risk, auto-execution ---
else {
  risk_level = 'LOW';
  status     = 'PENDING_AUTO_EXECUTION';
}

// 5. Determine routing tag for visual Switch node in n8n
//    This enables clean branching in Phase 2.
let routing_tag = '';

switch (risk_level) {
  case 'BLOCKED':
    routing_tag = 'ROUTE_TO_DEADLETTER';
    break;
  case 'HIGH':
    routing_tag = 'ROUTE_TO_HITL';   // Human in the Loop
    break;
  case 'MED':
    routing_tag = 'ROUTE_TO_CORE';   // Automated resolution with logging
    break;
  case 'LOW':
    routing_tag = 'ROUTE_TO_CORE';   // Straight-through processing
    break;
  default:
    routing_tag = 'ROUTE_TO_DEADLETTER'; // safety net
}

// 6. Enriched output for downstream nodes
return {
  json: {
    user,
    amount,
    intent,
    risk_level,
    status,
    routing_tag
  }
};

// ============================================================
// Phase 2.1 – Core Banking Execution & Simulation Layer
// This node acts as the final ledger, safely simulating banking
// actions based on intent and risk level.
// ============================================================

const originalTicket = $input.first().json;

try {
  // ----------------------------------------------------------
  // 1. Extract & normalise the incoming ticket fields
  // ----------------------------------------------------------
  const user        = originalTicket.user        || 'unknown';
  const intent      = originalTicket.intent      || 'general_inquiry';
  const risk_level  = originalTicket.risk_level  || 'LOW';
  const routing_tag = originalTicket.routing_tag || 'ROUTE_TO_DEADLETTER';

  // Amount is critical – ensure it's a valid number
  let amount = parseFloat(originalTicket.amount);
  if (isNaN(amount)) amount = 0;

  // We will overwrite the status field
  let status = originalTicket.status || 'PENDING';

  // ----------------------------------------------------------
  // 2. Execution Matrix – deterministic mock core responses
  // ----------------------------------------------------------
  let core_response = {};

  // --- Scenario A: Happy Path Transfer (low‑risk transfer intent) ---
  if (intent === 'transfer_request' && risk_level === 'LOW') {
    status = 'RESOLVED_AUTO';
    // Generate a unique transaction id (8 hex chars)
    const tx_id = 'TXN-' + Math.random().toString(16).substring(2, 10);
    core_response = {
      action:         'TRANSFER_EXECUTED',
      tx_id,          // the mock ledger entry id
      ledger_status:  'CLEARED',           // funds have moved
      timestamp:      new Date().toISOString()
    };
  }
  // --- Scenario B: Auto‑Refund for medium‑risk payment issues ---
  else if (intent === 'payment_issue' && risk_level === 'MED') {
    status = 'RESOLVED_AUTO_REFUND';
    core_response = {
      action:          'REFUND_ISSUED',
      amount_refunded: amount,             // full amount returned
      original_tx_id:  'UNKNOWN',          // no link to original (simulated)
      timestamp:       new Date().toISOString()
    };
  }
  // --- Scenario C: High‑risk tickets held for human approval ---
  else if (risk_level === 'HIGH') {
    status = 'LOCKED_AWAITING_APPROVAL';
    core_response = {
      action:      'HELD_IN_ESCROW',
      hold_reason: 'RISK_THRESHOLD_EXCEEDED',
      timestamp:   new Date().toISOString()
    };
  }
  // --- Scenario D: Fallback – all other combinations ---
  else {
    status = 'LOGGED_NO_ACTION';
    core_response = {
      action:    'NO_OP',
      timestamp: new Date().toISOString()
    };
  }

  // ----------------------------------------------------------
  // 3. Return the enriched, un‑mutated ticket
  //    Original fields are preserved; only status is updated
  //    and the core_response is appended.
  // ----------------------------------------------------------
  return {
    json: {
      user,
      amount,
      intent,
      risk_level,
      status,          // updated status reflecting the action taken
      routing_tag,     // preserved for potential post‑execution routing
      core_response     // cryptographically structured ledger entry
    }
  };

} catch (error) {
  // ----------------------------------------------------------
  // 4. Emergency fallback – core system fault
  //    The original ticket is returned intact, but flagged
  //    with a fault signature so operations can recover.
  // ----------------------------------------------------------
  return {
    json: {
      ...originalTicket,                        // carry forward all original data
      amount: parseFloat(originalTicket.amount) || 0,
      status: 'CORE_SYSTEM_FAULT',
      risk_level: originalTicket.risk_level || 'UNKNOWN',
      core_response: {
        action:        'CORE_SYSTEM_FAULT',
        error_message: error.message || 'Unhandled exception in core simulation',
        timestamp:     new Date().toISOString()
      }
    }
  };
}

// ============================================================
// Phase 2.2 – Telegram Payload Formatter (High‑Risk Alerts)
// Formats the HELD ticket into a Telegram‑ready payload with
// inline action buttons for human authorisation.
// ============================================================

const ticket     = $input.first().json;
const rawUser    = ticket.user       || 'unknown';
const rawIntent  = ticket.intent     || 'general_inquiry';

// Safely parse & format amount with thousand separators (UZS)
const rawAmount  = parseFloat(ticket.amount);
const amount     = isNaN(rawAmount) ? 0 : rawAmount;
const rawFormattedAmount = amount.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ',') + ' UZS';

// ------------------------------------------------------------
// 1. ESCAPE HELPER FOR TELEGRAM MARKDOWNV2
// Telegram MDv2 strictly requires these characters to be escaped:
// _ * [ ] ( ) ~ ` > # + - = | { } . !
// ------------------------------------------------------------
function escapeMD(text) {
  return String(text).replace(/[_*[\]()~`>#+\-=|{}.!]/g, '\\$&');
}

const user = escapeMD(rawUser);
const intent = escapeMD(rawIntent);
const formattedAmount = escapeMD(rawFormattedAmount);

// ------------------------------------------------------------
// 2. Build the notification text (MarkdownV2)
// ------------------------------------------------------------
const telegram_text =
  `🚨 *HIGH RISK TRANSACTION HELD* 🚨\n\n` +
  `*User:* ID\\-${user}\n` +
  `*Intent:* ${intent}\n` +
  `*Amount:* ${formattedAmount}\n` +
  `*Action Required:* Awaiting human authorisation\\.`;

// ------------------------------------------------------------
// 3. Construct the inline keyboard with callback data
// ------------------------------------------------------------
const telegram_markup = {
  inline_keyboard: [
    [
      { text: "✅ APPROVE", callback_data: `approve_${rawUser}` },
      { text: "❌ DENY",   callback_data: `deny_${rawUser}`   }
    ]
  ]
};

return {
  json: {
    telegram_text,
    telegram_markup
  }
};

const ticket = $input.first().json;
ticket.status = "TERMINATED_AT_FIREWALL";
return { json: ticket };

// ============================================================
// Sprint 3.1 & 4.1 – Unit Economics & Audit Logger
// Formats the completed ticket for the Audit Trail Google Sheet.
// ============================================================

const ticket       = $input.first().json;
const user_id      = ticket.user                || 'unknown';
const intent       = ticket.intent              || 'general_inquiry';
const risk_level   = ticket.risk_level          || 'LOW';
const final_status = ticket.status              || 'UNKNOWN';
const amount       = parseFloat(ticket.amount) || 0;

// ------------------------------------------------------------
// 1. Unit Economics Constants
// ------------------------------------------------------------
const MANUAL_COST_UZS = 15000;   // Cost of a human agent
const AI_COST_UZS     = 45;      // Cost of REVENANT processing

let processing_cost_uzs;
let money_saved_uzs;

const statusLower = final_status.toLowerCase();

// ------------------------------------------------------------
// 2. Determine processing cost & savings based on final status
// ------------------------------------------------------------
if (statusLower.includes('auto') || statusLower.includes('firewall')) {
  // Automated resolution – no human touch
  processing_cost_uzs = AI_COST_UZS;
  money_saved_uzs     = MANUAL_COST_UZS - AI_COST_UZS;
} else if (statusLower.includes('authorized') || statusLower.includes('denied')) {
  // Human-in-the-loop – full manual cost applies
  processing_cost_uzs = MANUAL_COST_UZS;
  money_saved_uzs     = 0;
} else {
  // Fallback (other statuses like LOGGED, CORE_SYSTEM_FAULT, etc.)
  processing_cost_uzs = AI_COST_UZS;  // assume automated handling by default
  money_saved_uzs     = MANUAL_COST_UZS - AI_COST_UZS;
}

// ------------------------------------------------------------
// 3. Compliance Tagging (Sprint 4.2)
// ------------------------------------------------------------
const audit_tags = [];

if (amount > 50000000) {
  audit_tags.push('AML_HARD_LIMIT_TRIGGERED');
}

if (risk_level === 'LOW') {
  audit_tags.push('KYC_VERIFIED', 'AUTO_CLEARED');
}

// Join tags into a single string for Google Sheets
const audit_tags_str = audit_tags.join(', ');

// ------------------------------------------------------------
// 4. Generate a fake ledger hash (audit trail reference)
// ------------------------------------------------------------
const randomHex = Array.from({ length: 16 }, () =>
  Math.floor(Math.random() * 16).toString(16)
).join('');
const ledger_hash = `SHA256-${randomHex}`;

// ------------------------------------------------------------
// 5. Final flat JSON for Google Sheets append row
// ------------------------------------------------------------
// ** CONNECT TO GOOGLE SHEETS NODE **
// After this node, add a "Google Sheets" node -> "Append Row".
// Map the following fields directly:
//   timestamp           -> {{ $json.timestamp }}
//   user_id             -> {{ $json.user_id }}
//   intent              -> {{ $json.intent }}
//   risk_level          -> {{ $json.risk_level }}
//   final_status        -> {{ $json.final_status }}
//   processing_cost_uzs -> {{ $json.processing_cost_uzs }}
//   money_saved_uzs     -> {{ $json.money_saved_uzs }}
//   audit_tags          -> {{ $json.audit_tags }}
//   ledger_hash         -> {{ $json.ledger_hash }}
// Make sure the sheet's first row has the exact same headers.
// ------------------------------------------------------------
return {
  json: {
    timestamp: new Date().toISOString(),
    user_id,
    intent,
    risk_level,
    final_status,
    processing_cost_uzs,
    money_saved_uzs,
    audit_tags: audit_tags_str,
    ledger_hash
  }
};
